import numpy as np
from collections import defaultdict

class SimpleWord2Vec:
    """Simplified Word2Vec with Skip-gram."""
    def __init__(self, vocab_size, embedding_dim=50):
        self.vocab_size = vocab_size
        self.embedding_dim = embedding_dim
        # Two embedding matrices (center and context)
        self.W_center = np.random.randn(vocab_size, embedding_dim) * 0.01
        self.W_context = np.random.randn(vocab_size, embedding_dim) * 0.01

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-np.clip(x, -10, 10)))

    def train_pair(self, center_idx, context_idx, learning_rate=0.01):
        # Forward pass
        h = self.W_center[center_idx]
        score = self.sigmoid(np.dot(self.W_context[context_idx], h))
        # Backward pass (gradient descent)
        error = score - 1  # target is 1 for positive pair
        self.W_context[context_idx] -= learning_rate * error * h
        self.W_center[center_idx] -= learning_rate * error * self.W_context[context_idx]

    def get_embedding(self, idx):
        return self.W_center[idx]

# Build vocabulary from corpus
corpus = [
    "the king is strong",
    "the queen is wise",
    "the king and queen rule",
    "a strong man and wise woman"
]

# Tokenize and build vocab
word_to_idx = {}
for sentence in corpus:
    for word in sentence.lower().split():
        if word not in word_to_idx:
            word_to_idx[word] = len(word_to_idx)

idx_to_word = {v: k for k, v in word_to_idx.items()}
vocab_size = len(word_to_idx)

# Generate skip-gram pairs (window size 2)
def get_skipgram_pairs(corpus, word_to_idx, window=2):
    pairs = []
    for sentence in corpus:
        words = sentence.lower().split()
        indices = [word_to_idx[w] for w in words]
        for i, center in enumerate(indices):
            for j in range(max(0, i-window), min(len(indices), i+window+1)):
                if i != j:
                    pairs.append((center, indices[j]))
    return pairs

pairs = get_skipgram_pairs(corpus, word_to_idx)
print(f"Vocabulary: {word_to_idx}")
print(f"Training pairs: {len(pairs)}")

# Train
model = SimpleWord2Vec(vocab_size, embedding_dim=10)
for epoch in range(100):
    for center, context in pairs:
        model.train_pair(center, context)

# Check similar words using cosine similarity
def cosine_sim(a, b):
    return np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b))

king_emb = model.get_embedding(word_to_idx['king'])
queen_emb = model.get_embedding(word_to_idx['queen'])
strong_emb = model.get_embedding(word_to_idx['strong'])

print(f"\nKing-Queen similarity: {cosine_sim(king_emb, queen_emb):.3f}")
print(f"King-Strong similarity: {cosine_sim(king_emb, strong_emb):.3f}")
