import re
from collections import defaultdict

# Simple rule-based NER
class RuleBasedNER:
    def __init__(self):
        self.patterns = {
            'PERSON': [r'\b[A-Z][a-z]+ [A-Z][a-z]+\b'],  # Two capitalized words
            'EMAIL': [r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'],
            'PHONE': [r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b'],
            'URL': [r'https?://[^\s]+'],
            'DATE': [r'\b\d{1,2}/\d{1,2}/\d{2,4}\b', r'\b\w+ \d{1,2},? \d{4}\b'],
            'MONEY': [r'\$\d+(?:,\d{3})*(?:\.\d{2})?']
        }

    def extract(self, text):
        entities = []
        for entity_type, patterns in self.patterns.items():
            for pattern in patterns:
                for match in re.finditer(pattern, text):
                    entities.append({
                        'text': match.group(),
                        'type': entity_type,
                        'start': match.start(),
                        'end': match.end()
                    })
        return sorted(entities, key=lambda x: x['start'])

# BIO tagging for sequence labeling
def bio_tag(text, entities):
    """Convert entity spans to BIO tags."""
    tokens = text.split()
    tags = ['O'] * len(tokens)
    char_to_token = {}
    pos = 0
    for i, token in enumerate(tokens):
        for j in range(len(token)):
            char_to_token[pos + j] = i
        pos += len(token) + 1  # +1 for space

    for entity in entities:
        start_token = char_to_token.get(entity['start'])
        end_token = char_to_token.get(entity['end'] - 1)
        if start_token is not None:
            tags[start_token] = f"B-{entity['type']}"
            for t in range(start_token + 1, (end_token or start_token) + 1):
                tags[t] = f"I-{entity['type']}"
    return list(zip(tokens, tags))

# Example
ner = RuleBasedNER()
text = "Contact John Smith at john@example.com or call 555-123-4567. Price is $1,250.00"
entities = ner.extract(text)

print("Entities found:")
for e in entities:
    print(f"  {e['type']:10s}: {e['text']}")

# BIO tags
tags = bio_tag(text, entities)
print("\nBIO Tags:")
for token, tag in tags:
    print(f"  {token:15s} {tag}")
